import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
  return {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date('2026-01-15T10:00:00Z'),
      updatedAt: new Date('2026-01-15T10:00:00Z'),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date('2026-01-15T10:00:00Z'),
    ...overrides,
  };
}

function makeStatusChangedEvent(overrides?: Partial<OrderStatusChangedEvent>): OrderStatusChangedEvent {
  return {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date('2026-01-15T10:00:00Z'),
      updatedAt: new Date('2026-01-15T10:00:00Z'),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date('2026-01-15T10:00:00Z'),
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let eventBus: EventBus;
  let logRepo: NotificationLogRepository;
  let historyService: NotificationHistoryService;
  let notificationService: NotificationService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    logRepo = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(logRepo);
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);
    notificationService.setHistoryService(historyService);
    resetNotificationIdCounter();
    resetLogIdCounter();
  });

  describe('logging via notification dispatch', () => {
    it('should log a sent notification', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.notificationId).toBe('notif-0001');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.type).toBe('order_confirmation');
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.sentAt).toBeInstanceOf(Date);
    });

    it('should log a failed notification when no adapter is registered', async () => {
      const noAdapterService = new NotificationService(new EventBus());
      const separateHistory = new NotificationHistoryService(new NotificationLogRepository(db));
      noAdapterService.setHistoryService(separateHistory);

      await noAdapterService.dispatch({
        recipient: 'bob@example.com',
        subject: 'Test',
        body: 'Test body',
        channel: 'sms',
        type: 'welcome',
      });

      const logs = separateHistory.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('failed');
      expect(logs[0]?.error).toContain('No adapter for channel');
    });

    it('should log multiple notifications from different events', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());

      expect(historyService.count()).toBe(2);
    });

    it('should capture metadata in the log', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.getAll();
      expect(logs[0]?.metadata).toEqual({ orderId: 'order-1', userId: 'user-1' });
    });

    it('should capture subject and body in the log', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.getAll();
      expect(logs[0]?.subject).toContain('Order Confirmation');
      expect(logs[0]?.body).toContain('Widget x2');
    });
  });

  describe('query by recipient', () => {
    it('should return logs for a specific recipient', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(
        makeOrderCreatedEvent({
          user: {
            id: 'user-2',
            name: 'Bob',
            email: 'bob@example.com',
            role: 'member',
            createdAt: new Date(),
            updatedAt: new Date(),
          },
        }),
      );

      const aliceLogs = historyService.getByRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(1);
      expect(aliceLogs[0]?.recipient).toBe('alice@example.com');

      const bobLogs = historyService.getByRecipient('bob@example.com');
      expect(bobLogs).toHaveLength(1);
    });

    it('should return empty array for unknown recipient', () => {
      const logs = historyService.getByRecipient('nobody@example.com');
      expect(logs).toHaveLength(0);
    });
  });

  describe('query by type', () => {
    it('should filter logs by notification type', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());

      const confirmations = historyService.query({ type: 'order_confirmation' });
      expect(confirmations).toHaveLength(1);
      expect(confirmations[0]?.type).toBe('order_confirmation');

      const updates = historyService.query({ type: 'order_status_update' });
      expect(updates).toHaveLength(1);
    });
  });

  describe('query by date range', () => {
    it('should filter logs by date range', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const inRange = historyService.query({
        from: new Date('2026-01-01'),
        to: new Date('2026-12-31'),
      });
      expect(inRange).toHaveLength(1);

      const outOfRange = historyService.query({
        from: new Date('2025-01-01'),
        to: new Date('2025-12-31'),
      });
      expect(outOfRange).toHaveLength(0);
    });
  });

  describe('query with combined filters', () => {
    it('should combine recipient and type filters', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());

      const results = historyService.query({
        recipient: 'alice@example.com',
        type: 'order_confirmation',
      });
      expect(results).toHaveLength(1);

      const noResults = historyService.query({
        recipient: 'alice@example.com',
        type: 'welcome',
      });
      expect(noResults).toHaveLength(0);
    });

    it('should filter by channel', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const emailLogs = historyService.query({ channel: 'email' });
      expect(emailLogs).toHaveLength(1);

      const smsLogs = historyService.query({ channel: 'sms' });
      expect(smsLogs).toHaveLength(0);
    });

    it('should filter by status', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const sentLogs = historyService.query({ status: 'sent' });
      expect(sentLogs).toHaveLength(1);

      const failedLogs = historyService.query({ status: 'failed' });
      expect(failedLogs).toHaveLength(0);
    });

    it('should filter by userId in metadata', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const results = historyService.query({ userId: 'user-1' });
      expect(results).toHaveLength(1);

      const noResults = historyService.query({ userId: 'user-999' });
      expect(noResults).toHaveLength(0);
    });
  });

  describe('getByNotificationId', () => {
    it('should find a log by notification ID', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const log = historyService.getByNotificationId('notif-0001');
      expect(log).toBeDefined();
      expect(log?.recipient).toBe('alice@example.com');
    });

    it('should return undefined for unknown notification ID', () => {
      const log = historyService.getByNotificationId('notif-9999');
      expect(log).toBeUndefined();
    });
  });

  describe('welcome notification logging', () => {
    it('should log welcome notifications from user:created events', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-5',
          name: 'Charlie',
          email: 'charlie@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const logs = historyService.query({ type: 'welcome' });
      expect(logs).toHaveLength(1);
      expect(logs[0]?.recipient).toBe('charlie@example.com');
      expect(logs[0]?.status).toBe('sent');
    });
  });

  describe('backward compatibility', () => {
    it('should work without history service set', async () => {
      const plainService = new NotificationService(eventBus);
      plainService.registerAdapter(emailAdapter);

      await eventBus.emit(makeOrderCreatedEvent());

      // NotificationService still works, just no logging
      const notifications = plainService.getNotifications();
      expect(notifications).toHaveLength(1);
    });
  });
});

